const seen = new Map();
const nodeNames = ['GDELT caff\u00e8', 'GDELT proteste', 'GDELT porti', 'GDELT politica', 'GDELT disastri'];

for (const name of nodeNames) {
  try {
    const items = $(name).all();
    for (const item of items) {
      const articles = item.json.articles || [];
      for (const art of articles) {
        if (art.url && !seen.has(art.url)) {
          seen.set(art.url, art);
        }
      }
    }
  } catch(e) {}
}

return [{ json: { articles: Array.from(seen.values()) } }];

