const raw = $json.data || '';
const sourceUrl = 'https://psl.noaa.gov/data/correlation/oni.data';
const now = new Date().toISOString();
const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const rows = [];
for (const line of raw.split(/\r?\n/)) {
  const parts = line.trim().split(/\s+/);
  if (parts.length < 13) continue;

  const year = Number(parts[0]);
  if (!Number.isInteger(year) || year < 1950) continue;

  for (let i = 0; i < months.length; i++) {
    const value = Number(parts[i + 1]);
    if (Number.isNaN(value) || value < -10) continue;

    rows.push({
      year,
      month: months[i],
      month_number: i + 1,
      period: `${year}-${String(i + 1).padStart(2, '0')}`,
      period_label: `${year}-${months[i]}`,
      oni_value: Number(value.toFixed(2))
    });
  }
}

if (!rows.length) {
  throw new Error('No valid ONI values parsed from NOAA ENSO file');
}

const latest = rows[rows.length - 1];
const recentSeries = rows.slice(-24);

let ensoPhase = 'NEUTRAL';
let phaseStrength = 'neutral';
let alertLevel = 'LOW';
let impactForecast = 'No major ENSO-driven climate disruptions expected.';
let northNortheastImpact = 'No strong ENSO-driven anomaly signaled.';
let southImpact = 'No strong ENSO-driven anomaly signaled.';
let summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a neutral ENSO phase. No major ENSO-driven climate disruption is currently signaled for Brazil.`;
let signals = [
  'ENSO phase neutral',
  `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
  'No major ENSO-driven disruption signaled for Brazil'
];

if (latest.oni_value >= 0.5) {
  ensoPhase = 'EL_NINO';
  alertLevel = 'MODERATE';
  phaseStrength = 'moderate';
  impactForecast = 'Possible water shortages in North and Northeast Brazil; increased rainfall in Southern Brazil.';
  northNortheastImpact = 'Drier and hotter conditions with higher drought and wildfire risk.';
  southImpact = 'Wetter conditions with higher heavy-rain and flooding risk.';
  summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating El Nino conditions. Brazil faces higher drought pressure in North and Northeast regions and higher rainfall risk in the South.`;
  signals = [
    'ENSO phase El Nino',
    `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
    'North and Northeast Brazil drought risk elevated',
    'Southern Brazil heavy rainfall risk elevated'
  ];

  if (latest.oni_value >= 1.5) {
    alertLevel = 'CRITICAL';
    phaseStrength = 'strong';
    impactForecast = 'High risk of drought in Amazon and Northeast Brazil; severe flood risk in Southern Brazil.';
    northNortheastImpact = 'Strong drought and wildfire pressure across Amazon and Northeast Brazil.';
    southImpact = 'Strong heavy-rain and flood pressure in Southern Brazil.';
    summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a strong El Nino phase. Brazil faces severe drought pressure in Amazon and Northeast regions and severe flood risk in the South.`;
    signals = [
      'ENSO phase strong El Nino',
      `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
      'Amazon and Northeast Brazil drought risk critical',
      'Southern Brazil flood risk critical'
    ];
  }
} else if (latest.oni_value <= -0.5) {
  ensoPhase = 'LA_NINA';
  alertLevel = 'MODERATE';
  phaseStrength = 'moderate';
  impactForecast = 'Drier conditions likely in Southern Brazil; wetter conditions in North and Northeast Brazil.';
  northNortheastImpact = 'Wetter conditions with higher river flooding risk.';
  southImpact = 'Drier conditions with higher agricultural drought risk.';
  summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating La Nina conditions. Brazil faces higher dryness risk in the South and wetter conditions in North and Northeast regions.`;
  signals = [
    'ENSO phase La Nina',
    `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
    'Southern Brazil drought risk elevated',
    'North and Northeast Brazil flood risk elevated'
  ];

  if (latest.oni_value <= -1.5) {
    alertLevel = 'CRITICAL';
    phaseStrength = 'strong';
    impactForecast = 'High risk of drought in Southern Brazil crops; flood risk in North and Northeast Brazil.';
    northNortheastImpact = 'Strong wet conditions with flood pressure in North and Northeast Brazil.';
    southImpact = 'Strong agricultural drought pressure in Southern Brazil.';
    summaryEn = `Latest NOAA ONI reading for ${latest.period_label} is ${latest.oni_value.toFixed(2)}, indicating a strong La Nina phase. Brazil faces critical southern dryness pressure and elevated flood risk in North and Northeast regions.`;
    signals = [
      'ENSO phase strong La Nina',
      `Latest ONI anomaly ${latest.oni_value.toFixed(2)}`,
      'Southern Brazil crop drought risk critical',
      'North and Northeast Brazil flood risk elevated'
    ];
  }
}

return [{
  json: {
    source: 'NOAA_ENSO',
    source_url: sourceUrl,
    country: 'BR',
    macroarea: 'environment',
    collected_at: now,
    latest_period: latest.period,
    latest_period_label: latest.period_label,
    latest_year: latest.year,
    latest_month: latest.month,
    latest_month_number: latest.month_number,
    oni_value: latest.oni_value,
    enso_phase: ensoPhase,
    phase_strength: phaseStrength,
    alert_level: alertLevel,
    impact_forecast: impactForecast,
    brazil_impact_north_northeast: northNortheastImpact,
    brazil_impact_south: southImpact,
    summary_en: summaryEn,
    signals,
    history_window_months: recentSeries.length,
    recent_series: recentSeries
  }
}];

const now = new Date().toISOString();
return [{
  json: {
    source: 'NOAA_ENSO',
    country: 'BR',
    run_date: now,
    status: 'done',
    completed_at: now
  }
}];

const raw = $json.data || '';
const now = new Date().toISOString();
const sensor = 'VIIRS_SNPP_NRT';
const lookbackDays = 5;
const bbox = '-75,-35,-33,6';
const sourceUrlTemplate = `https://firms.modaps.eosdis.nasa.gov/api/area/csv/[NASA_FIRMS_KEY]/${sensor}/${bbox}/${lookbackDays}`;

function parseCsvLine(line) {
  const values = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      if (inQuotes && line[i + 1] === '"') {
        current += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === ',' && !inQuotes) {
      values.push(current);
      current = '';
    } else {
      current += char;
    }
  }

  values.push(current);
  return values;
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

function buildDetectionUtc(acqDate, acqTime) {
  if (!acqDate) return null;
  const time = String(acqTime || '').padStart(4, '0');
  const hh = time.slice(0, 2);
  const mm = time.slice(2, 4);
  return `${acqDate}T${hh}:${mm}:00Z`;
}

function percentile(sortedValues, p) {
  if (!sortedValues.length) return null;
  const index = Math.min(sortedValues.length - 1, Math.max(0, Math.ceil(sortedValues.length * p) - 1));
  return Number(sortedValues[index].toFixed(2));
}

const lines = raw.split(/\r?\n/).filter((line) => line.trim() !== '');
if (!lines.length) {
  throw new Error('NASA FIRMS response is empty');
}

const headers = parseCsvLine(lines[0]).map((header) => header.trim());
const requiredHeaders = ['latitude', 'longitude', 'acq_date', 'acq_time', 'frp'];
for (const header of requiredHeaders) {
  if (!headers.includes(header)) {
    throw new Error(`Unexpected NASA FIRMS CSV schema: missing ${header}`);
  }
}

const numericFields = new Set(['latitude', 'longitude', 'bright_ti4', 'bright_ti5', 'scan', 'track', 'frp']);

const detections = lines.slice(1).map((line) => {
  const values = parseCsvLine(line);
  const row = {};

  headers.forEach((header, index) => {
    const rawValue = (values[index] ?? '').trim();
    row[header] = numericFields.has(header) ? toNumber(rawValue) : rawValue;
  });

  row.acq_time = String(row.acq_time || '').padStart(4, '0');
  row.detection_utc = buildDetectionUtc(row.acq_date, row.acq_time);

  return row;
}).filter((row) => row.latitude !== null && row.longitude !== null && row.acq_date);

const totalDetections = detections.length;
const detectionsByDay = {};
const confidenceCounts = {};
const daynightCounts = {};
const satelliteCounts = {};

for (const detection of detections) {
  const acqDate = detection.acq_date || 'unknown';
  const confidence = String(detection.confidence || 'unknown');
  const daynight = String(detection.daynight || 'unknown');
  const satellite = String(detection.satellite || 'unknown');

  detectionsByDay[acqDate] = (detectionsByDay[acqDate] || 0) + 1;
  confidenceCounts[confidence] = (confidenceCounts[confidence] || 0) + 1;
  daynightCounts[daynight] = (daynightCounts[daynight] || 0) + 1;
  satelliteCounts[satellite] = (satelliteCounts[satellite] || 0) + 1;
}

const frpValues = detections.map((detection) => detection.frp).filter((value) => typeof value === 'number');
const sortedFrpValues = [...frpValues].sort((a, b) => a - b);
const frpSum = frpValues.reduce((sum, value) => sum + value, 0);
const maxFrp = sortedFrpValues.length ? Number(sortedFrpValues[sortedFrpValues.length - 1].toFixed(2)) : null;
const minFrp = sortedFrpValues.length ? Number(sortedFrpValues[0].toFixed(2)) : null;
const avgFrp = sortedFrpValues.length ? Number((frpSum / sortedFrpValues.length).toFixed(2)) : null;
const p95Frp = percentile(sortedFrpValues, 0.95);
const smallFrpLt50Count = frpValues.filter((value) => value < 50).length;
const extremeFrpGte500Count = frpValues.filter((value) => value >= 500).length;

const detectionUtcValues = detections.map((detection) => detection.detection_utc).filter(Boolean).sort();
const earliestDetectionUtc = detectionUtcValues.length ? detectionUtcValues[0] : null;
const latestDetectionUtc = detectionUtcValues.length ? detectionUtcValues[detectionUtcValues.length - 1] : null;
const latestDay = Object.keys(detectionsByDay).sort().slice(-1)[0] || null;
const latestDayCount = latestDay ? detectionsByDay[latestDay] : 0;

const topDetectionsByFrp = [...detections]
  .filter((detection) => typeof detection.frp === 'number')
  .sort((a, b) => b.frp - a.frp)
  .slice(0, 20)
  .map((detection) => ({
    latitude: detection.latitude,
    longitude: detection.longitude,
    acq_date: detection.acq_date,
    acq_time: detection.acq_time,
    detection_utc: detection.detection_utc,
    frp: detection.frp,
    confidence: detection.confidence || null,
    daynight: detection.daynight || null,
    satellite: detection.satellite || null,
    instrument: detection.instrument || null,
    bright_ti4: detection.bright_ti4 ?? null,
    bright_ti5: detection.bright_ti5 ?? null
  }));

const topDays = Object.entries(detectionsByDay)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([date, count]) => ({ date, count }));

let summaryEn = `NASA FIRMS returned ${totalDetections} fire detections in the Brazil bounding box over the last ${lookbackDays} days.`;
const signals = [`${totalDetections} FIRMS detections in Brazil bbox over ${lookbackDays} days`];

if (totalDetections > 0) {
  summaryEn += ` Max FRP was ${maxFrp ?? 'n/a'} MW, ${extremeFrpGte500Count} detections were at or above 500 MW, and the latest detection timestamp was ${latestDetectionUtc || 'n/a'}.`;
  signals.push(`Max FRP ${maxFrp ?? 'n/a'} MW`);
  signals.push(`${extremeFrpGte500Count} detections at or above 500 MW`);
  if (latestDay) {
    signals.push(`${latestDayCount} detections on latest day ${latestDay}`);
  }
} else {
  summaryEn += ' No active fire detections were returned for the configured area and lookback window.';
  signals.push('No detections returned in current FIRMS query window');
}

return [{
  json: {
    source: 'NASA_FIRMS',
    source_format: 'csv',
    source_url_template: sourceUrlTemplate,
    country: 'BR',
    macroarea: 'environment',
    collected_at: now,
    sensor,
    bbox,
    lookback_days: lookbackDays,
    records_schema: headers,
    total_detections: totalDetections,
    earliest_detection_utc: earliestDetectionUtc,
    latest_detection_utc: latestDetectionUtc,
    latest_day: latestDay,
    latest_day_count: latestDayCount,
    detections_by_day: detectionsByDay,
    top_days_by_detection_count: topDays,
    confidence_counts: confidenceCounts,
    daynight_counts: daynightCounts,
    satellite_counts: satelliteCounts,
    frp_stats: {
      min_mw: minFrp,
      avg_mw: avgFrp,
      max_mw: maxFrp,
      p95_mw: p95Frp,
      small_lt_50_count: smallFrpLt50Count,
      extreme_gte_500_count: extremeFrpGte500Count
    },
    top_detections_by_frp: topDetectionsByFrp,
    summary_en: summaryEn,
    signals,
    detections
  }
}];

const now = new Date().toISOString();
return [{
  json: {
    source: 'NASA_FIRMS',
    country: 'BR',
    run_date: now,
    status: 'done',
    completed_at: now
  }
}];

const now = new Date().toISOString();
const lookbackDays = 10;
const end = new Date();
const start = new Date(end);
start.setDate(start.getDate() - lookbackDays);

function formatIsoDate(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  if (Number.isNaN(numeric)) return null;
  return Number(numeric.toFixed(decimals));
}

const responseRows = Array.isArray($json.value) ? $json.value : [];
const rows = responseRows
  .map((row) => {
    const dataHoraCotacao = String(row.dataHoraCotacao || '').trim();
    const cotacaoCompra = toNumber(row.cotacaoCompra, 4);
    const cotacaoVenda = toNumber(row.cotacaoVenda, 4);

    return {
      dataHoraCotacao,
      quote_date: dataHoraCotacao ? dataHoraCotacao.slice(0, 10) : null,
      cotacaoCompra,
      cotacaoVenda,
      spread: cotacaoCompra !== null && cotacaoVenda !== null ? Number((cotacaoVenda - cotacaoCompra).toFixed(4)) : null
    };
  })
  .filter((row) => row.dataHoraCotacao && row.cotacaoCompra !== null && row.cotacaoVenda !== null)
  .sort((a, b) => a.dataHoraCotacao.localeCompare(b.dataHoraCotacao));

if (!rows.length) {
  throw new Error('BCB PTAX returned no valid quotes in the selected period');
}

const latest = rows[rows.length - 1];
const previous = rows.length > 1 ? rows[rows.length - 2] : null;
const recentSeries = rows.slice(-10);
const sellValues = rows.map((row) => row.cotacaoVenda).filter((value) => typeof value === 'number');
const minSell = sellValues.length ? Number(Math.min(...sellValues).toFixed(4)) : null;
const maxSell = sellValues.length ? Number(Math.max(...sellValues).toFixed(4)) : null;
const avgSell = sellValues.length ? Number((sellValues.reduce((sum, value) => sum + value, 0) / sellValues.length).toFixed(4)) : null;
const rangeSell = minSell !== null && maxSell !== null ? Number((maxSell - minSell).toFixed(4)) : null;

const changeVsPrevious = previous ? Number((latest.cotacaoVenda - previous.cotacaoVenda).toFixed(4)) : null;
const changePctVsPrevious = previous && previous.cotacaoVenda ? Number((((latest.cotacaoVenda - previous.cotacaoVenda) / previous.cotacaoVenda) * 100).toFixed(4)) : null;

let movementLabel = 'stable';
let summaryEn = `Latest BCB PTAX USD/BRL fixing on ${latest.quote_date} was ${latest.cotacaoVenda.toFixed(4)} BRL sell and ${latest.cotacaoCompra.toFixed(4)} BRL buy.`;
const signals = [
  `Latest PTAX sell ${latest.cotacaoVenda.toFixed(4)} BRL/USD`,
  `Latest PTAX buy ${latest.cotacaoCompra.toFixed(4)} BRL/USD`,
  `10-day sell range ${rangeSell !== null ? rangeSell.toFixed(4) : 'n/a'} BRL`
];

if (changeVsPrevious !== null) {
  if (changeVsPrevious > 0) movementLabel = 'brl_weaker';
  else if (changeVsPrevious < 0) movementLabel = 'brl_stronger';

  summaryEn += ` Versus the previous fixing, the PTAX sell rate changed by ${changeVsPrevious.toFixed(4)} BRL (${changePctVsPrevious.toFixed(4)}%).`;
  if (movementLabel === 'brl_weaker') {
    summaryEn += ' This indicates BRL weakening against the USD versus the previous fixing.';
    signals.push('BRL weakened versus previous PTAX fixing');
  } else if (movementLabel === 'brl_stronger') {
    summaryEn += ' This indicates BRL strengthening against the USD versus the previous fixing.';
    signals.push('BRL strengthened versus previous PTAX fixing');
  } else {
    signals.push('PTAX unchanged versus previous fixing');
  }
}

return [{
  json: {
    source: 'BCB_PTAX',
    source_format: 'odata_json',
    source_url_template: 'https://olinda.bcb.gov.br/olinda/servico/PTAX/versao/v1/odata/CotacaoDolarPeriodo(...)',
    country: 'BR',
    macroarea: 'prices',
    collected_at: now,
    lookback_days: lookbackDays,
    query_start_date: formatIsoDate(start),
    query_end_date: formatIsoDate(end),
    total_quotes: rows.length,
    quote_date: latest.quote_date,
    dataHoraCotacao: latest.dataHoraCotacao,
    cotacaoCompra: latest.cotacaoCompra,
    cotacaoVenda: latest.cotacaoVenda,
    spread: latest.spread,
    movement_label: movementLabel,
    previous_quote_date: previous ? previous.quote_date : null,
    previous_dataHoraCotacao: previous ? previous.dataHoraCotacao : null,
    previous_cotacaoCompra: previous ? previous.cotacaoCompra : null,
    previous_cotacaoVenda: previous ? previous.cotacaoVenda : null,
    change_vs_previous: changeVsPrevious,
    change_pct_vs_previous: changePctVsPrevious,
    sell_stats_lookback: {
      min: minSell,
      avg: avgSell,
      max: maxSell,
      range: rangeSell
    },
    recent_series: recentSeries,
    summary_en: summaryEn,
    signals
  }
}];

const now = new Date().toISOString();
return [{
  json: {
    source: 'BCB_PTAX',
    country: 'BR',
    run_date: now,
    status: 'done',
    completed_at: now
  }
}];

