const latestMonth = Number(updated.monthNumber);

if (!Number.isInteger(latestYear) || !Number.isInteger(latestMonth) || latestMonth < 1 || latestMonth > 12) {
  throw new Error('Comex Stat updated endpoint returned invalid year/month');
}

function pad(value) {
  return String(value).padStart(2, '0');
}

function shiftPeriod(year, month, offsetMonths) {
  const date = new Date(Date.UTC(year, month - 1 + offsetMonths, 1));
  return {
    year: date.getUTCFullYear(),
    month: date.getUTCMonth() + 1,
    period: date.getUTCFullYear() + '-' + pad(date.getUTCMonth() + 1),
  };
}

const latestPeriod = shiftPeriod(latestYear, latestMonth, 0);
const previousPeriod = shiftPeriod(latestYear, latestMonth, -1);
const sameMonthPreviousYear = shiftPeriod(latestYear, latestMonth, -12);
const startPeriod = shiftPeriod(latestYear, latestMonth, -23);

