const now = new Date().toISOString();
const meta = $('Comex Build Query Params').item.json;
const updatedResponse = $('Comex Updated Check').item.json;
const stateSeriesResponse = $('Comex State Series').item.json;
const destinationResponse = $('Comex Destination Snapshot').item.json;

const GREEN_CODES = new Set(meta.ncm_groups.green);
const ROASTED_CODES = new Set(meta.ncm_groups.roasted);
const SOLUBLE_CODES = new Set(meta.ncm_groups.soluble);
const FOCUS_STATES = [
  { key: 'minas gerais', name: 'Minas Gerais' },
  { key: 'espirito santo', name: 'Espírito Santo' },
  { key: 'bahia', name: 'Bahia' },
  { key: 'rondonia', name: 'Rondônia' },
];

function round(value, decimals = 4) {
  if (value === null || value === undefined || Number.isNaN(value)) return null;
  return Number(Number(value).toFixed(decimals));
}

function pad(value) {
  return String(value).padStart(2, '0');
}

function extractRows(payload) {
  if (Array.isArray(payload)) return payload;
  if (payload && payload.data && Array.isArray(payload.data.list)) return payload.data.list;
  if (payload && payload.data && Array.isArray(payload.data)) return payload.data;
  if (payload && Array.isArray(payload.list)) return payload.list;
  return [];
}

function normalizeText(value) {
  return String(value ?? '').trim();
}

function normalizeStateKey(value) {
  return normalizeText(value)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function toNumber(value, decimals = 4) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number') return Number.isFinite(value) ? round(value, decimals) : null;
  const raw = normalizeText(value);
  if (!raw) return null;
  const cleaned = raw.includes(',')
    ? raw.replace(/\./g, '').replace(',', '.')
    : raw;
  const numeric = Number(cleaned);
  return Number.isNaN(numeric) ? null : round(numeric, decimals);
}

function pctChange(current, previous, decimals = 4) {
  if (current === null || previous === null || previous === 0) return null;
  return round(((current - previous) / previous) * 100, decimals);
}

function sharePct(part, total, decimals = 4) {
  if (part === null || total === null || total === 0) return null;
  return round((part / total) * 100, decimals);
}

function sharePpChange(current, previous, decimals = 4) {
  if (current === null || previous === null) return null;
  return round(current - previous, decimals);
}

function formatNumber(value, decimals = 2) {
  return value === null ? 'n/a' : Number(value).toFixed(decimals);
}

function extractNcmCode(value) {
  const raw = normalizeText(value);
  if (!raw) return null;
  const match = raw.match(/\b(\d{8})\b/);
  if (match) return match[1];
  const digits = raw.replace(/\D/g, '');
  if (digits.length === 8) return digits;
  return null;
}

function classifyProductGroup(ncmCode) {
  if (!ncmCode) return 'unknown';
  if (GREEN_CODES.has(ncmCode) || /^090111|^090112/.test(ncmCode)) return 'green';
  if (ROASTED_CODES.has(ncmCode) || /^090121|^090122/.test(ncmCode)) return 'roasted';
  if (SOLUBLE_CODES.has(ncmCode) || /^210111|^210112/.test(ncmCode)) return 'soluble';
  return 'unknown';
}

function buildEmptyMetricBucket() {
  return {
    fob_usd: 0,
    kg: 0,
    statistic_qty: 0,
  };
}

function getMetricBucket(container, key) {
  if (!container[key]) container[key] = buildEmptyMetricBucket();
  return container[key];
}

function addMetrics(bucket, row) {
  bucket.fob_usd += row.metric_fob_usd || 0;
  bucket.kg += row.metric_kg || 0;
  bucket.statistic_qty += row.metric_statistic || 0;
}

function finalizeBucket(bucket, totalFob, totalKg) {
  return {
    fob_usd: round(bucket.fob_usd, 2),
    kg: round(bucket.kg, 2),
    statistic_qty: round(bucket.statistic_qty, 2),
    share_fob_pct: sharePct(bucket.fob_usd, totalFob, 4),
    share_kg_pct: sharePct(bucket.kg, totalKg, 4),
  };
}

function avgPrice(fob, kg) {
  if (fob === null || kg === null || kg === 0) return null;
  return round(fob / kg, 6);
}

function sortPeriods(a, b) {
  return a.localeCompare(b);
}

function normalizeRow(row, kind) {
  const year = Number(row.year);
  const month = Number(row.monthNumber || meta.latest_available_month);
  if (!Number.isInteger(year) || !Number.isInteger(month)) return null;
  const period = year + '-' + pad(month);
  const ncmCode = extractNcmCode(row.ncm || row.coNcm || row.ncmCode || '');

  return {
    kind,
    year,
    month,
    period,
    state: normalizeText(row.state || row.stateName || ''),
    state_key: normalizeStateKey(row.state || row.stateName || ''),
    country: normalizeText(row.country || row.countryName || ''),
    ncm_raw: normalizeText(row.ncm || row.coNcm || row.ncmCode || ''),
    ncm_code: ncmCode,
    product_group: classifyProductGroup(ncmCode),
    metric_fob_usd: toNumber(row.metricFOB, 2) || 0,
    metric_kg: toNumber(row.metricKG, 2) || 0,
    metric_statistic: toNumber(row.metricStatistic, 2) || 0,
  };
}

const rawStateRows = extractRows(stateSeriesResponse).map((row) => normalizeRow(row, 'state')).filter(Boolean);
const rawDestinationRows = extractRows(destinationResponse).map((row) => normalizeRow(row, 'destination')).filter(Boolean);

if (!rawStateRows.length) throw new Error('Comex State Series returned no valid rows');
if (!rawDestinationRows.length) throw new Error('Comex Destination Snapshot returned no valid rows');

const periodMap = new Map();
for (const row of rawStateRows) {
  const periodEntry = periodMap.get(row.period) || {
    period: row.period,
    year: row.year,
    month: row.month,
    total_exports_fob_usd: 0,
    total_exports_kg: 0,
    total_exports_statistic_qty: 0,
    by_group: {},
    by_state: new Map(),
  };

  periodEntry.total_exports_fob_usd += row.metric_fob_usd;
  periodEntry.total_exports_kg += row.metric_kg;
  periodEntry.total_exports_statistic_qty += row.metric_statistic;
  addMetrics(getMetricBucket(periodEntry.by_group, row.product_group), row);

  if (row.state_key) {
    const stateEntry = periodEntry.by_state.get(row.state_key) || {
      state: row.state,
      bucket: buildEmptyMetricBucket(),
    };
    addMetrics(stateEntry.bucket, row);
    periodEntry.by_state.set(row.state_key, stateEntry);
  }

  periodMap.set(row.period, periodEntry);
}

const periods = Array.from(periodMap.keys()).sort(sortPeriods);
const latestPeriod = meta.latest_available_period;
const previousPeriod = meta.previous_period;
const yoyPeriod = meta.same_month_previous_year;

const latestAgg = periodMap.get(latestPeriod);
if (!latestAgg) throw new Error('Comex parser could not find latest period in state series');
const previousAgg = periodMap.get(previousPeriod) || null;
const yoyAgg = periodMap.get(yoyPeriod) || null;

function finalizePeriod(entry) {
  if (!entry) return null;
  const productMix = {
    green: finalizeBucket(getMetricBucket(entry.by_group, 'green'), entry.total_exports_fob_usd, entry.total_exports_kg),
    roasted: finalizeBucket(getMetricBucket(entry.by_group, 'roasted'), entry.total_exports_fob_usd, entry.total_exports_kg),
    soluble: finalizeBucket(getMetricBucket(entry.by_group, 'soluble'), entry.total_exports_fob_usd, entry.total_exports_kg),
    unknown: finalizeBucket(getMetricBucket(entry.by_group, 'unknown'), entry.total_exports_fob_usd, entry.total_exports_kg),
  };

  return {
    period: entry.period,
    total_exports_fob_usd: round(entry.total_exports_fob_usd, 2),
    total_exports_kg: round(entry.total_exports_kg, 2),
    total_exports_statistic_qty: round(entry.total_exports_statistic_qty, 2),
    avg_fob_usd_per_kg: avgPrice(entry.total_exports_fob_usd, entry.total_exports_kg),
    product_mix: productMix,
  };
}

const latestFinal = finalizePeriod(latestAgg);
const previousFinal = finalizePeriod(previousAgg);
const yoyFinal = finalizePeriod(yoyAgg);

const focusStates = FOCUS_STATES.map((focusState) => {
  const stateEntry = latestAgg.by_state.get(focusState.key);
  const bucket = stateEntry ? stateEntry.bucket : buildEmptyMetricBucket();
  return {
    state: focusState.name,
    fob_usd: round(bucket.fob_usd, 2),
    kg: round(bucket.kg, 2),
    statistic_qty: round(bucket.statistic_qty, 2),
    share_fob_pct: sharePct(bucket.fob_usd, latestAgg.total_exports_fob_usd, 4),
    share_kg_pct: sharePct(bucket.kg, latestAgg.total_exports_kg, 4),
  };
});

const focusStatesFobTotal = focusStates.reduce((sum, row) => sum + (row.fob_usd || 0), 0);
const focusStatesKgTotal = focusStates.reduce((sum, row) => sum + (row.kg || 0), 0);

const destinationsMap = new Map();
for (const row of rawDestinationRows.filter((entry) => entry.period === latestPeriod)) {
  const key = row.country || 'Unknown';
  const destination = destinationsMap.get(key) || {
    country: key,
    bucket: buildEmptyMetricBucket(),
  };
  addMetrics(destination.bucket, row);
  destinationsMap.set(key, destination);
}

const topDestinations = Array.from(destinationsMap.values())
  .map((entry) => ({
    country: entry.country,
    fob_usd: round(entry.bucket.fob_usd, 2),
    kg: round(entry.bucket.kg, 2),
    statistic_qty: round(entry.bucket.statistic_qty, 2),
    share_fob_pct: sharePct(entry.bucket.fob_usd, latestAgg.total_exports_fob_usd, 4),
    share_kg_pct: sharePct(entry.bucket.kg, latestAgg.total_exports_kg, 4),
  }))
  .sort((a, b) => (b.fob_usd || 0) - (a.fob_usd || 0))
  .slice(0, 10);

const topDestinationSharePct = topDestinations.length ? topDestinations[0].share_fob_pct : null;
const top3DestinationsFob = topDestinations.slice(0, 3).reduce((sum, row) => sum + (row.fob_usd || 0), 0);
const top3DestinationsSharePct = sharePct(top3DestinationsFob, latestAgg.total_exports_fob_usd, 4);

const recentSeries = periods.slice(-meta.lookback_months).map((period) => {
  const entry = periodMap.get(period);
  const finalized = finalizePeriod(entry);
  return {
    period: finalized.period,
    total_exports_fob_usd: finalized.total_exports_fob_usd,
    total_exports_kg: finalized.total_exports_kg,
    total_exports_statistic_qty: finalized.total_exports_statistic_qty,
    avg_fob_usd_per_kg: finalized.avg_fob_usd_per_kg,
    green_share_kg_pct: finalized.product_mix.green.share_kg_pct,
    roasted_share_kg_pct: finalized.product_mix.roasted.share_kg_pct,
    soluble_share_kg_pct: finalized.product_mix.soluble.share_kg_pct,
  };
});

const momExportsKgPct = previousFinal ? pctChange(latestFinal.total_exports_kg, previousFinal.total_exports_kg) : null;
const momExportsFobPct = previousFinal ? pctChange(latestFinal.total_exports_fob_usd, previousFinal.total_exports_fob_usd) : null;
const yoyExportsKgPct = yoyFinal ? pctChange(latestFinal.total_exports_kg, yoyFinal.total_exports_kg) : null;
const yoyExportsFobPct = yoyFinal ? pctChange(latestFinal.total_exports_fob_usd, yoyFinal.total_exports_fob_usd) : null;
const avgPriceMomPct = previousFinal ? pctChange(latestFinal.avg_fob_usd_per_kg, previousFinal.avg_fob_usd_per_kg) : null;
const avgPriceYoYPct = yoyFinal ? pctChange(latestFinal.avg_fob_usd_per_kg, yoyFinal.avg_fob_usd_per_kg) : null;
const greenShareChangePpYoY = yoyFinal ? sharePpChange(latestFinal.product_mix.green.share_kg_pct, yoyFinal.product_mix.green.share_kg_pct) : null;
const roastedShareChangePpYoY = yoyFinal ? sharePpChange(latestFinal.product_mix.roasted.share_kg_pct, yoyFinal.product_mix.roasted.share_kg_pct) : null;
const solubleShareChangePpYoY = yoyFinal ? sharePpChange(latestFinal.product_mix.soluble.share_kg_pct, yoyFinal.product_mix.soluble.share_kg_pct) : null;

const signals = [];
if (yoyExportsKgPct !== null && yoyExportsKgPct >= 10) signals.push('export_volume_yoy_up');
if (yoyExportsKgPct !== null && yoyExportsKgPct <= -10) signals.push('export_volume_yoy_down');
if (yoyExportsFobPct !== null && yoyExportsFobPct >= 10) signals.push('export_value_yoy_up');
if (yoyExportsFobPct !== null && yoyExportsFobPct <= -10) signals.push('export_value_yoy_down');
if (avgPriceYoYPct !== null && avgPriceYoYPct >= 10) signals.push('average_export_price_rising');
if (avgPriceYoYPct !== null && avgPriceYoYPct <= -10) signals.push('average_export_price_falling');
if (solubleShareChangePpYoY !== null && solubleShareChangePpYoY >= 3) signals.push('soluble_share_rising');
if (roastedShareChangePpYoY !== null && roastedShareChangePpYoY >= 2) signals.push('roasted_share_rising');
if (top3DestinationsSharePct !== null && top3DestinationsSharePct >= 60) signals.push('destination_concentration_high');
if (sharePct(focusStatesKgTotal, latestAgg.total_exports_kg, 4) !== null && sharePct(focusStatesKgTotal, latestAgg.total_exports_kg, 4) >= 80) signals.push('focus_states_export_concentration_high');
if (yoyExportsFobPct !== null && yoyExportsFobPct >= 10 && yoyExportsKgPct !== null && Math.abs(yoyExportsKgPct) < 5) signals.push('export_value_up_volume_flat');

let movementLabel = 'mixed';
if ((solubleShareChangePpYoY !== null && solubleShareChangePpYoY >= 3) || (roastedShareChangePpYoY !== null && roastedShareChangePpYoY >= 2) || (greenShareChangePpYoY !== null && greenShareChangePpYoY <= -3)) {
  movementLabel = 'mix_shift';
} else if ((yoyExportsKgPct !== null && yoyExportsKgPct >= 10) || (momExportsKgPct !== null && momExportsKgPct >= 10)) {
  movementLabel = 'export_pressure_rising';
} else if ((yoyExportsKgPct !== null && yoyExportsKgPct <= -10) || (momExportsKgPct !== null && momExportsKgPct <= -10)) {
  movementLabel = 'export_pressure_easing';
}

const focusStatesShareKgPct = sharePct(focusStatesKgTotal, latestAgg.total_exports_kg, 4);
const focusStatesShareFobPct = sharePct(focusStatesFobTotal, latestAgg.total_exports_fob_usd, 4);

let riskLevel = 'low';
const riskScore = [
  yoyExportsKgPct !== null && yoyExportsKgPct >= 10,
  top3DestinationsSharePct !== null && top3DestinationsSharePct >= 60,
  focusStatesShareKgPct !== null && focusStatesShareKgPct >= 80,
  avgPriceYoYPct !== null && avgPriceYoYPct >= 10,
].filter(Boolean).length;
if (riskScore >= 3) riskLevel = 'high';
else if (riskScore >= 1) riskLevel = 'medium';

const dominantGroup = ['green', 'roasted', 'soluble', 'unknown']
  .map((group) => ({
    group,
    share: latestFinal.product_mix[group].share_kg_pct || 0,
  }))
  .sort((a, b) => b.share - a.share)[0];

let summaryEn = 'Latest Comex Stat export snapshot for ' + latestFinal.period + ' shows ' + formatNumber(latestFinal.total_exports_kg, 2) + ' kg and ' + formatNumber(latestFinal.total_exports_fob_usd, 2) + ' USD FOB in Brazilian coffee exports.';
if (dominantGroup && dominantGroup.group !== 'unknown') {
  summaryEn += ' ' + dominantGroup.group.charAt(0).toUpperCase() + dominantGroup.group.slice(1) + ' coffee accounted for ' + formatNumber(dominantGroup.share, 2) + '% of export volume.';
}
if (previousFinal) {
  summaryEn += ' Versus ' + previousFinal.period + ', export volume changed by ' + formatNumber(momExportsKgPct, 4) + '% and export value by ' + formatNumber(momExportsFobPct, 4) + '%.';
}
if (yoyFinal) {
  summaryEn += ' Versus ' + yoyFinal.period + ', export volume changed by ' + formatNumber(yoyExportsKgPct, 4) + '% and the average export price by ' + formatNumber(avgPriceYoYPct, 4) + '%.';
}
if (topDestinations.length) {
  summaryEn += ' The top destination was ' + topDestinations[0].country + '.';
}

const recentTailPeriods = new Set(periods.slice(-6));

return [{
  json: {
    source: 'COMEX_STAT',
    source_format: 'json_api',
    source_base_url: meta.source_base_url,
    source_updated_date: meta.source_updated_date,
    country: 'BR',
    macroarea: 'crops',
    flow: 'export',
    collected_at: now,
    updated_reference: {
      updated: meta.source_updated_date,
      year: meta.latest_available_year,
      month: meta.latest_available_month,
      period: meta.latest_available_period,
    },
    lookback_months: meta.lookback_months,
    ncm_codes: meta.ncm_codes,
    ncm_groups: meta.ncm_groups,
    latest_month: {
      period: latestFinal.period,
      total_exports_fob_usd: latestFinal.total_exports_fob_usd,
      total_exports_kg: latestFinal.total_exports_kg,
      total_exports_statistic_qty: latestFinal.total_exports_statistic_qty,
      avg_fob_usd_per_kg: latestFinal.avg_fob_usd_per_kg,
    },
    previous_month: previousFinal ? {
      period: previousFinal.period,
      total_exports_fob_usd: previousFinal.total_exports_fob_usd,
      total_exports_kg: previousFinal.total_exports_kg,
      total_exports_statistic_qty: previousFinal.total_exports_statistic_qty,
      avg_fob_usd_per_kg: previousFinal.avg_fob_usd_per_kg,
    } : null,
    same_month_previous_year: yoyFinal ? {
      period: yoyFinal.period,
      total_exports_fob_usd: yoyFinal.total_exports_fob_usd,
      total_exports_kg: yoyFinal.total_exports_kg,
      total_exports_statistic_qty: yoyFinal.total_exports_statistic_qty,
      avg_fob_usd_per_kg: yoyFinal.avg_fob_usd_per_kg,
    } : null,
    product_mix: {
      green: latestFinal.product_mix.green,
      roasted: latestFinal.product_mix.roasted,
      soluble: latestFinal.product_mix.soluble,
    },
    focus_states,
    top_destinations: topDestinations,
    derived_metrics: {
      mom_exports_kg_pct: momExportsKgPct,
      mom_exports_fob_pct: momExportsFobPct,
      yoy_exports_kg_pct: yoyExportsKgPct,
      yoy_exports_fob_pct: yoyExportsFobPct,
      avg_price_mom_pct: avgPriceMomPct,
      avg_price_yoy_pct: avgPriceYoYPct,
      green_share_change_pp_yoy: greenShareChangePpYoY,
      roasted_share_change_pp_yoy: roastedShareChangePpYoY,
      soluble_share_change_pp_yoy: solubleShareChangePpYoY,
      top_destination_share_pct: topDestinationSharePct,
      top_3_destinations_share_pct: top3DestinationsSharePct,
      focus_states_share_fob_pct: focusStatesShareFobPct,
      focus_states_share_kg_pct: focusStatesShareKgPct,
    },
    movement_label: movementLabel,
    risk_level: riskLevel,
    signals: Array.from(new Set(signals)),
    summary_en: summaryEn,
    recent_series: recentSeries,
    raw_rows_latest_month_destinations: rawDestinationRows.filter((row) => row.period === latestPeriod).slice(0, 100),
    raw_rows_state_series_tail: rawStateRows.filter((row) => recentTailPeriods.has(row.period)).slice(0, 250),
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw
  .replace(/^```json\\s*/i, '')
  .replace(/^```\\s*/i, '')
  .replace(/```$/i, '')
  .trim();
const parsed = JSON.parse(cleaned);
const base = $('Comex Parse').item.json;

return [{
  json: {
    ...base,
    rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
    rule_based_movement_label: base.movement_label || 'mixed',
    rule_based_risk_level: base.risk_level || 'low',
    fallback_summary_en: base.summary_en || '',
    movement_label: parsed.movement_label || base.movement_label || 'mixed',
    risk_level: parsed.risk_level || base.risk_level || 'low',
    signals: Array.isArray(parsed.signals) ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
    summary_en: parsed.summary_en || base.summary_en || '',
  },
}];

const now = new Date().toISOString();
const meta = $('Comex Parse Signals').item.json;

return [{
  json: {
    source: 'COMEX_STAT',
    country: 'BR',
    macroarea: 'crops',
    run_date: now,
    status: 'done',
    completed_at: now,
    report_period: meta.updated_reference ? meta.updated_reference.period : null,
  },
}];
